class Solution:
    def __init__(self, nums: List[int]):
        self.idx = defaultdict(list)
        for i, x in enumerate(nums):
            self.idx[x].append(i)
    def pick(self, target: int) -> int:
        arr = self.idx[target]
        return arr[random.randint(0, len(arr)-1)]

