class Solution {
    unordered_map<int, vector<int>> idx;
public:
    Solution(vector<int>& nums) {
        for (int i = 0; i < (int)nums.size(); i++) idx[nums[i]].push_back(i);
    }
    int pick(int target) {
        auto& v = idx[target];
        return v[rand() % v.size()];
    }
};

