typedef struct {
    int* nums; int n;
} Solution;
Solution* solutionCreate(int* nums, int n) {
    Solution* s = malloc(sizeof(Solution)); s->nums = nums; s->n = n; return s;
}
int solutionPick(Solution* obj, int target) {
    int cnt = 0, ans = 0;
    for (int i = 0; i < obj->n; i++)
        if (obj->nums[i] == target) {
            cnt++;
            if (rand() % cnt == 0) ans = i;
        }
    return ans;
}
